const cfg = $('Config').first().json;
const base = String(cfg.backendUrl || '').replace(/\/$/, '');
if (!base) {
  throw new Error('Config.backendUrl es requerido');
}

const limit = Number(cfg.fetchLimit) || 50;
const items = [];
let offset = 0;

while (true) {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/api/captures/new`,
    qs: { limit, offset },
    json: true,
  });

  if (!res?.ok || !Array.isArray(res.items) || res.items.length === 0) {
    break;
  }

  for (const capture of res.items) {
    items.push({
      json: {
        ...capture,
        backendUrl: base,
        frontendUrl: cfg.frontendUrl,
        n8nUrl: cfg.n8nUrl,
        backendRoot: cfg.backendRoot,
        n8nFilesRoot: cfg.n8nFilesRoot,
        processedDir: cfg.processedDir,
        estadoFinal: cfg.estadoFinal,
        openAiImageModel: cfg.openAiImageModel,
      },
    });
  }

  const total = res.pagination?.total ?? items.length;
  offset += limit;
  if (offset >= total) {
    break;
  }
}

return items;

const PROMPT_TEMPLATE = `Create a highly detailed cartoon-style portrait based on a real selfie photo. Preserve the person's real identity, facial structure, skin tone, hairstyle, and main facial features, but exaggerate the detected emotion in a humorous and expressive cartoon way.

Emotion detected: {{ emocion }}
Confidence level: {{ porcentaje }}

Apply the emotional intensity according to the confidence percentage:
- 0–40% → subtle emotion
- 41–70% → noticeable emotion
- 71–100% → highly exaggerated emotional expression

Supported emotions:
- Happiness
- Sadness
- Anger
- Surprise
- Fear
- Disgust

Emotion behavior rules:

Happiness:
- Big smile
- Bright eyes
- Cheerful expression
- Comic hearts, stars, sparkles

Sadness:
- Tears
- Pouty lips
- Sad eyebrows
- Rain cloud, dramatic mood

Anger:
- Red face tones
- Angry eyebrows
- Steam/smoke effects
- Intense expression lines

Surprise:
- Wide open eyes
- Open mouth
- Shock lines
- Dynamic comic effects

Fear:
- Nervous eyes
- Sweat drops
- Pale tones
- Tension effects

Disgust:
- Scrunched nose
- Uneasy expression
- Greenish comic accents
- Reaction lines

Visual Style:
- Semi-realistic cartoon
- Pixar + comic illustration mix
- High detail skin texture
- Expressive emotional caricature
- Cinematic lighting
- Clean soft background
- Funny but visually appealing
- Ultra detailed
- 4K digital illustration

Important:
- Keep the person recognizable
- Do not completely distort the face
- Preserve realism while exaggerating emotion
- Add comic/cartoon effects matching the emotion
- Emotion intensity must reflect the confidence percentage`;

const item = $input.first().json;
const n8nFilesRoot = String(item.n8nFilesRoot || '/files').replace(//$/, '');
const processedDir = item.processedDir || 'procesed';
const apiBase = String(item.backendUrl || '').replace(//$/, '');

const fc = item.fechaCaptura || item.createdAt || new Date().toISOString();
const d = new Date(fc);
let dateFolder;
if (Number.isNaN(d.getTime())) {
  const now = new Date();
  dateFolder = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + String(now.getDate()).padStart(2, '0');
} else {
  dateFolder = d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
}

const originalName = item.nombreArchivo || ('capture-' + item.id + '.png');
const ext = (originalName.match(/\.[^.]+$/) || ['.png'])[0];
const baseName = originalName.replace(/\.[^.]+$/, '');
const outputName = baseName + '-caricatura' + ext;

// Ruta que guardas en BD/backend, relativa a tu carpeta pública del backend
const rutaAlmacenamientoDivertida = processedDir + '/' + dateFolder + '/' + outputName;

// Ruta real dentro del contenedor n8n. /files está montado hacia:
// /app/projects/uefn-backend/procesed en el Droplet
const rutaAbsolutaDivertida = n8nFilesRoot + '/' + dateFolder + '/' + outputName;

const emocion = String(item.emocion || 'neutral').trim();
const porcentaje = item.nivelConfianza ?? 0;

const prompt = PROMPT_TEMPLATE
  .replace(/\{\{\s*emocion\s*\}\}/gi, emocion)
  .replace(/\{\{\s*porcentaje\s*\}\}/gi, String(porcentaje));

const rel = item.rutaAlmacenamiento ? String(item.rutaAlmacenamiento).replace(/\/g, '/') : '';
const imageUrl = item.imageUrl || (rel ? apiBase + '/media/' + rel : null);

if (!imageUrl) {
  throw new Error('Captura ' + item.id + ' sin ruta_almacenamiento / imageUrl');
}

return [{
  json: {
    ...item,
    dateFolder,
    outputName,
    prompt,
    emocion,
    porcentaje,
    rutaAlmacenamientoDivertida,
    rutaAbsolutaDivertida,
    imageUrl,
  },
}];

const prep = $('Preparar rutas y prompt').first().json;
const openAi = $input.first().json;

const b64 = openAi?.data?.[0]?.b64_json;
if (!b64) {
  throw new Error('OpenAI no devolvio b64_json. Respuesta: ' + JSON.stringify(openAi).slice(0, 500));
}

const buffer = Buffer.from(b64, 'base64');

return [{
  json: prep,
  binary: {
    data: await this.helpers.prepareBinaryData(buffer, prep.outputName, 'image/png'),
  },
}];
